import { Hono } from 'hono';
import { z, ZodTypeAny } from 'zod';

const app = new Hono();

// Define task schema for validation
const TaskSchema: ZodTypeAny = z.object({
  id: z.string(),
  title: z.string(),
  description: z.string().optional(),
  createdAt: z.date(),
  updatedAt: z.date(),
  deletedAt: z.date().nullable()
});

// Mock database to store tasks
let tasks: any[] = [];

// Middleware to validate task data
const validateTask = (schema: ZodTypeAny) => {
  return async (c: any) => {
    const body = await c.req.json();
    const result = schema.safeParse(body);
    if (!result.success) {
      return c.json({ error: result.error.issues }, 400);
    }
    return c.next();
  };
};

// Middleware to find task by ID
const findTaskById = async (c: any) => {
  const taskId = c.req.param('id');
  const task = tasks.find(t => t.id === taskId);
  if (!task) {
    return c.json({ error: 'Task not found' }, 404);
  }
  c.set('task', task);
  return c.next();
};

// Create a new task
app.post('/tasks', validateTask(TaskSchema), async (c) => {
  const body = await c.req.json();
  const task = { ...body, createdAt: new Date(), updatedAt: new Date() };
  tasks.push(task);
  return c.json(task, 201);
});

// Get all tasks
app.get('/tasks', async (c) => {
  return c.json(tasks.filter(t => !t.deletedAt));
});

// Get a single task by ID
app.get('/tasks/:id', findTaskById, async (c) => {
  const task = c.get('task');
  return c.json(task);
});

// Update a task
app.put('/tasks/:id', validateTask(TaskSchema), findTaskById, async (c) => {
  const body = await c.req.json();
  const task = c.get('task');
  Object.assign(task, { ...body, updatedAt: new Date() });
  return c.json(task);
});

// Soft-delete a task
app.patch('/tasks/:id', findTaskById, async (c) => {
  const task = c.get('task');
  task.deletedAt = new Date();
  return c.json(task);
});

// Hard-delete a task (not implemented)
app.delete('/tasks/:id', findTaskById, async (c) => {
  const taskId = c.req.param('id');
  tasks = tasks.filter(t => t.id !== taskId);
  return c.json({ message: 'Task deleted' }, 204);
});

export default app;

